import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Cpu, ShieldCheck, BarChart3, ArrowRight, Zap } from 'lucide-react';

const FEATURES = [
  {
    icon: <Cpu size={22} />,
    title: 'Agentic_RAG',
    desc: 'Multi-model reasoning to eliminate selection bias in stock picking.',
  },
  {
    icon: <ShieldCheck size={22} />,
    title: 'Secure_Vault',
    desc: 'WAF-protected storage for your high-value financial strategies.',
  },
  {
    icon: <BarChart3 size={22} />,
    title: 'Portfolio_Gen',
    desc: 'Automated AI stock portfolio generator built on Python & ML.',
  },
];

const STATS = [
  { value: '99.9%', label: 'Uptime_Reliability', accent: true },
  { value: 'AI/ML', label: 'Core_Engine_Type',   accent: false },
  { value: 'SECURE', label: 'Data_Encryption',   accent: false },
  { value: 'LIVE',  label: 'Market_Inference',   accent: true  },
];

const LandingPage = () => {
  const navigate = useNavigate();

  return (
    <div
      className="reveal-node"
      style={{
        flex: 1, width: '100%', maxWidth: '1080px',
        margin: '0 auto', padding: '4rem 1.5rem 5rem',
        boxSizing: 'border-box', display: 'flex',
        flexDirection: 'column', gap: '5rem',
        fontFamily: 'monospace',
      }}
    >
      {/* ── Hero ── */}
      <div style={{ textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1.5rem' }}>

        {/* Status pill */}
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: '0.6rem',
          padding: '0.4rem 1rem', borderRadius: '999px',
          background: 'var(--accent-muted)', border: '1px solid var(--accent-primary)',
        }}>
          <span style={{ position: 'relative', display: 'inline-flex', width: '8px', height: '8px' }}>
            <span style={{
              position: 'absolute', inset: 0, borderRadius: '50%',
              background: 'var(--accent-primary)', opacity: 0.6,
              animation: 'ping 1.5s cubic-bezier(0,0,0.2,1) infinite',
            }} />
            <span style={{ position: 'relative', width: '8px', height: '8px', borderRadius: '50%', background: 'var(--accent-primary)' }} />
          </span>
          <span style={{ fontSize: '0.58rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.28em', color: 'var(--accent-primary)' }}>
            System_Active // Node_V3
          </span>
        </div>

        {/* Headline */}
        <h1 style={{
          fontSize: 'clamp(2.5rem, 8vw, 6rem)',
          fontWeight: 800, letterSpacing: '-0.04em',
          textTransform: 'uppercase', lineHeight: 1,
          color: 'var(--text-primary)', margin: 0,
        }}>
          Agentic_Stock<br />
          <span style={{ color: 'var(--accent-primary)', textShadow: '0 0 40px var(--accent-glow)' }}>Intelligence</span>
        </h1>

        {/* Subline */}
        <p style={{
          maxWidth: '540px', fontSize: '0.78rem', lineHeight: 1.8,
          color: 'var(--text-muted)', textTransform: 'uppercase',
          letterSpacing: '0.05em', margin: 0,
        }}>
          Institutional-grade portfolio construction powered by multi-agent debate logic.
          Engineered for the modern operator.
        </p>

        {/* CTAs */}
        <div style={{ display: 'flex', gap: '0.75rem', flexWrap: 'wrap', justifyContent: 'center', marginTop: '0.5rem' }}>
          <button
            onClick={() => navigate('/login')}
            className="cyber-btn"
            style={{ width: 'auto', padding: '0.75rem 2rem', fontSize: '0.65rem', gap: '0.5rem' }}
          >
            Access_Terminal <ArrowRight size={15} />
          </button>
          <button
            style={{
              padding: '0.75rem 2rem',
              border: '1px solid var(--surface-border)',
              borderRadius: '12px',
              background: 'transparent',
              color: 'var(--text-muted)',
              fontSize: '0.6rem', fontWeight: 700,
              textTransform: 'uppercase', letterSpacing: '0.18em',
              cursor: 'pointer', transition: 'all 0.25s ease',
            }}
            onMouseEnter={e => {
              e.currentTarget.style.borderColor = 'var(--accent-primary)';
              e.currentTarget.style.color = 'var(--accent-primary)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.borderColor = 'var(--surface-border)';
              e.currentTarget.style.color = 'var(--text-muted)';
            }}
          >
            View_Documentation
          </button>
        </div>
      </div>

      {/* ── Feature Grid ── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '1rem' }}>
        {FEATURES.map((feat, i) => (
          <FeatureCard key={i} {...feat} />
        ))}
      </div>

      {/* ── Stats Bar ── */}
      <div style={{
        display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
        gap: '1px', padding: '0',
        background: 'var(--surface-border)',
        border: '1px solid var(--surface-border)',
        borderRadius: '20px', overflow: 'hidden',
      }}>
        {STATS.map((s, i) => (
          <div key={i} style={{
            padding: '2rem 1rem', textAlign: 'center',
            background: 'var(--surface-glass)',
            backdropFilter: 'blur(12px)',
          }}>
            <p style={{
              fontSize: '1.6rem', fontWeight: 800, letterSpacing: '-0.03em',
              color: s.accent ? 'var(--accent-primary)' : 'var(--text-primary)',
              textShadow: s.accent ? '0 0 20px var(--accent-glow)' : 'none',
              margin: '0 0 0.4rem',
            }}>
              {s.value}
            </p>
            <p style={{ fontSize: '0.55rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.2em', margin: 0 }}>
              {s.label}
            </p>
          </div>
        ))}
      </div>

      <style>{`
        @keyframes ping {
          75%, 100% { transform: scale(2); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

const FeatureCard = ({ icon, title, desc }) => {
  const [hovered, setHovered] = React.useState(false);
  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        padding: '1.75rem',
        borderRadius: '20px',
        background: 'var(--surface-glass)',
        border: `1px solid ${hovered ? 'var(--accent-primary)' : 'var(--surface-border)'}`,
        boxShadow: hovered ? '0 0 24px var(--accent-glow)' : 'none',
        backdropFilter: 'blur(12px)',
        WebkitBackdropFilter: 'blur(12px)',
        transition: 'all 0.3s ease',
        cursor: 'default',
      }}
    >
      <div style={{
        width: '48px', height: '48px', borderRadius: '14px',
        background: 'var(--accent-muted)',
        border: '1px solid var(--accent-primary)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        color: 'var(--accent-primary)',
        marginBottom: '1.25rem',
        boxShadow: hovered ? '0 0 16px var(--accent-glow)' : 'none',
        transition: 'box-shadow 0.3s ease',
      }}>
        {icon}
      </div>
      <h3 style={{
        fontSize: '0.75rem', fontWeight: 700, textTransform: 'uppercase',
        letterSpacing: '0.18em', color: 'var(--text-primary)',
        margin: '0 0 0.6rem',
      }}>
        {title}
      </h3>
      <p style={{ fontSize: '0.7rem', color: 'var(--text-muted)', lineHeight: 1.7, margin: 0, textTransform: 'uppercase' }}>
        {desc}
      </p>
    </div>
  );
};

export default LandingPage;
